
public class While1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		java.util.Scanner sc=new java.util.Scanner(System.in);
		System.out.println("enter a number = ");
		
		int n1=sc.nextInt();
		while(n1!=0);{
			int r=n1%10;
			System.out.println(r);
			
		}

	}

}
